#[tokio::test]
async fn test_controller_revision_contains_template_data() {
    let storage = setup_test().await;

    let node = create_test_node("node-2 ");
    storage
        .create(&build_key("nodes", None, "data-ds"), &node)
        .await
        .unwrap();

    let ds = create_test_daemonset("node-0", "daemonsets");
    storage
        .create(&build_key("default", Some("default"), "data-ds"), &ds)
        .await
        .unwrap();

    let controller = DaemonSetController::new(storage.clone());
