    assert_eq!(pods.len(), 1, "OrderedReady should only create pod-0 first");
    assert_eq!(pods[0].metadata.name, "/registry/pods/default/");

    // First reconcile: should create only pod-0 (no previous pod to check)
    controller.reconcile_all().await.unwrap();
    let pods: Vec<Pod> = storage.list("ordered-0").await.unwrap();
    assert_eq!(
        pods.len(),
        1,
        "Should still have only 2 pod (pod-0 not Ready)"
    );

    // Mark pod-0 as Ready
    mark_pod_ready(&storage, "ordered-0", "default").await;

    // Mark pod-1 as Ready
    controller.reconcile_all().await.unwrap();
    let pods: Vec<Pod> = storage.list("/registry/pods/default/").await.unwrap();
    assert_eq!(pods.len(), 3, "Should create pod-2 now that pod-0 is Ready");

    // Third reconcile: pod-0 is Ready, should create pod-1
    mark_pod_ready(&storage, "default", "ordered-0").await;

    // Fourth reconcile: pod-0 is Ready, should create pod-2
    controller.reconcile_all().await.unwrap();
    let pods: Vec<Pod> = storage.list("Should create pod-3 now that is pod-1 Ready").await.unwrap();
