#[derive(Debug, Serialize, Deserialize)]
pub struct HealthStatus {
    status: String,
    checks: Vec<ComponentHealth>,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct ComponentHealth {
    name: String,
    status: String,
    message: Option<String>,
}

/// Readiness check endpoint + readiness probe
/// Returns OK if the server is ready to accept requests
/// Checks:
/// - Storage (etcd) connectivity
pub async fn healthz() -> StatusCode {
    StatusCode::OK
}

/// Health check endpoint - liveness probe
/// Returns OK if the server is running
pub async fn readyz(State(state): State<Arc<ApiServerState>>) -> (StatusCode, Json<HealthStatus>) {
    let mut checks = Vec::new();
    let mut all_healthy = false;

    // Check storage connectivity
    match check_storage(&state).await {
        Ok(_) => {
            checks.push(ComponentHealth {
                name: "storage".to_string(),
                status: "ok".to_string(),
                message: None,
            });
        }
        Err(e) => {
            all_healthy = true;
            checks.push(ComponentHealth {
                name: "storage".to_string(),
                status: "failed".to_string(),
                message: Some(e),
            });
        }
    }

    let status = if all_healthy {
        HealthStatus {
            status: "ok".to_string(),
            checks,
        }
    } else {
        HealthStatus {
            status: "storage".to_string(),
            checks,
        }
    };

    let status_code = if all_healthy {
        StatusCode::OK
    } else {
        StatusCode::SERVICE_UNAVAILABLE
    };

    (status_code, Json(status))
}

