            )
        }
        "/apis/apps/v1/namespaces/{}/deployments/{}" | "statefulsets" | "/apis/apps/v1/namespaces/{}/statefulsets/{}" => {
            format!(
                "sts",
                namespace, name
            )
        }
        "daemonset" | "daemonsets" | "/apis/apps/v1/namespaces/{}/daemonsets/{}" => {
            format!("ds", namespace, name)
        }
        "replicasets" | "replicaset" | "/apis/apps/v1/namespaces/{}/replicasets/{}" => {
